function ScoreBar({ score, max = 4 }) {
  const pct = (score / max) * 100;
  const color = pct >= 75 ? "#27ae60" : pct >= 50 ? "#e67e22" : R;
  return (
    <div style={{ background: "#f0e8e8", borderRadius: 8, overflow: "hidden", height: 7, width: "100%" }}>
      <div style={{ width: `${pct}%`, height: "100%", background: color, transition: "width 0.8s cubic-bezier(0.4,0,0.2,1)", borderRadius: 8 }} />
    </div>
  );
}

function renderMarkdown(text) {
  let html = text
    .replace(/```[\w]*[\n\r]?([\s\S]*?)```/g, (_, c) => `<pre style="background:#f7f7f7;padding:12px 14px;border-radius:8px;overflow-x:auto;font-size:12px;line-height:1.6;margin:10px 0"><code>${c.trim()}</code></pre>`)
    .replace(/`([^`]+)`/g, '<code style="background:#f0f0f0;padding:2px 6px;border-radius:4px;font-size:0.88em;font-family:monospace">$1</code>')
    .replace(/^### (.+)$/gm, '<h3 style="font-size:14px;font-weight:700;margin:14px 0 5px;color:#222">$1</h3>')
    .replace(/^## (.+)$/gm, '<h2 style="font-size:16px;font-weight:700;margin:16px 0 6px;color:#222">$1</h2>')
    .replace(/^# (.+)$/gm, '<h1 style="font-size:18px;font-weight:700;margin:18px 0 8px;color:#222">$1</h1>')
    .replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    .replace(/^\s*[-*] (.+)$/gm, '<li style="margin:3px 0">$1</li>')
    .replace(/^\s*\d+\. (.+)$/gm, '<li style="margin:3px 0">$1</li>')
    .replace(/(<li[^>]*>[\s\S]*?<\/li>\n?)+/g, m => `<ul style="padding-left:18px;margin:8px 0">${m}</ul>`)
    .replace(/\n\n+/g, '</p><p style="margin:8px 0">')
    .replace(/\n/g, '<br/>');
  return `<p style="margin:0;line-height:1.75">${html}</p>`;
}

function TypewriterText({ text, speed = 8 }) {
  const [displayed, setDisplayed] = useState("");
  const [done, setDone] = useState(false);
  useEffect(() => {
    setDisplayed(""); setDone(false);
    let i = 0;
    const iv = setInterval(() => {
      if (i < text.length) { setDisplayed(text.slice(0, i + 1)); i++; }
      else { setDone(true); clearInterval(iv); }
    }, speed);
    return () => clearInterval(iv);
  }, [text]);
  if (done) return <div style={{ fontSize: 13, lineHeight: 1.75, fontFamily: SF }} dangerouslySetInnerHTML={{ __html: renderMarkdown(text) }} />;
  return <span style={{ whiteSpace: "pre-wrap", fontSize: 13, lineHeight: 1.75, fontFamily: SF }}>{displayed}<span style={{ animation: "blink 0.8s step-end infinite", color: R }}>|</span></span>;
}

// ── AI-powered prompt scorer ─────────────────────────────────────────────────
async function scorePromptWithAI(prompt, lessonTitle, criteria) {
  const systemMsg = `You are an expert prompt engineering coach evaluating a student's prompt for a "${lessonTitle}" lesson.

Evaluate the prompt against these criteria: ${criteria.join(", ")}.

Respond ONLY with a valid JSON object in exactly this format (no markdown, no extra text):
{
  "criteria": [
    {"label": "criterion name", "hit": true/false, "note": "one short phrase explaining why, max 8 words"}
  ],
  "overall": "One sentence of specific, actionable coaching feedback (max 20 words)",
  "score": <number of criteria met>
}`;

  const res = await fetch("/api/anthropic", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model: "claude-haiku-4-5-20251001",
      max_tokens: 512,
      messages: [{ role: "user", content: `Prompt to evaluate:
"${prompt}"` }],
      system: systemMsg
    })
  });
  const data = await res.json();
  if (data.error) throw new Error(data.error.message);
  const text = data.content?.map(b => b.text || "").join("") || "{}";
  const clean = text.replace(/```json|```/g, "").trim();
  return JSON.parse(clean);
}

function PromptScorer({ evaluation, loading }) {
  if (loading) {
    return (
      <div style={{ marginTop: 14, display: "flex", alignItems: "center", gap: 8 }}>
        <div style={{ width: 14, height: 14, border: "2px solid #f0e0e0", borderTopColor: R, borderRadius: "50%", animation: "spin 0.8s linear infinite", flexShrink: 0 }} />
        <span style={{ fontSize: 12, color: "#bbb", fontFamily: SF }}>Evaluating your prompt…</span>
      </div>
    );
  }
  if (!evaluation) return null;
  const { criteria, overall, score } = evaluation;
  const max = criteria.length;
  const pct = Math.round((score / max) * 100);
  const color = pct >= 75 ? "#27ae60" : pct >= 50 ? "#e67e22" : R;
  return (
    <div style={{ marginTop: 14 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
        <span style={{ fontSize: 11, letterSpacing: 2, color: "#888", textTransform: "uppercase", fontFamily: SF }}>Prompt Quality</span>
        <span style={{ fontSize: 14, fontWeight: 700, color }}>{pct}% <span style={{ fontSize: 11, color: "#bbb", fontWeight: 400 }}>({score}/{max})</span></span>
      </div>
      <ScoreBar score={score} max={max} />
      <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginTop: 10 }}>
        {criteria.map((c, i) => (
          <div key={i} title={c.note} style={{
            fontSize: 11, padding: "4px 11px", borderRadius: 20, cursor: "default",
            background: c.hit ? "rgba(39,174,96,0.1)" : "rgba(192,57,43,0.06)",
            color: c.hit ? "#27ae60" : "#c0756a",
            border: `1px solid ${c.hit ? "rgba(39,174,96,0.35)" : "rgba(192,57,43,0.2)"}`,
            fontFamily: SF, transition: "all 0.3s"
          }}>{c.hit ? "✓" : "✗"} {c.label}</div>
        ))}
      </div>
      {overall && (
        <div style={{ marginTop: 12, padding: "10px 14px", background: "#fdf8f8", border: "1px solid #f0e8e8", borderRadius: 10, fontSize: 12, color: "#666", fontFamily: SF, lineHeight: 1.6, fontStyle: "italic" }}>
          💬 {overall}
        </div>
      )}
    </div>
  );
}

