// ── Highlight-to-save tooltip ─────────────────────────────────────────────────
function HighlightLayer({ onSave }) {
  const [tooltip, setTooltip] = useState(null);

  useEffect(() => {
    const handleMouseUp = (e) => {
      const sel = window.getSelection();
      if (!sel || sel.isCollapsed) { setTooltip(null); return; }
      const text = sel.toString().trim();
      if (text.length < 10) { setTooltip(null); return; }
      // Don't show on form elements
      const node = sel.anchorNode?.parentElement;
      if (node?.closest("textarea, input, button")) { setTooltip(null); return; }
      setTooltip({ text, x: e.clientX, y: e.clientY });
    };
    const handleMouseDown = (e) => {
      if (!e.target.closest("[data-highlight-tooltip]")) setTooltip(null);
    };
    document.addEventListener("mouseup", handleMouseUp);
    document.addEventListener("mousedown", handleMouseDown);
    return () => { document.removeEventListener("mouseup", handleMouseUp); document.removeEventListener("mousedown", handleMouseDown); };
  }, []);

  if (!tooltip) return null;
  return (
    <div data-highlight-tooltip="true" style={{
      position: "fixed", left: tooltip.x - 60, top: tooltip.y - 52, zIndex: 9999,
      background: "#1a0505", borderRadius: 10, padding: "8px 14px",
      boxShadow: "0 4px 20px rgba(0,0,0,0.2)", display: "flex", alignItems: "center", gap: 8,
      animation: "fadeUp 0.15s ease"
    }}>
      <span style={{ fontSize: 12, color: "#fff", fontFamily: SF }}>Save to Notes</span>
      <button onClick={() => { onSave(tooltip.text); setTooltip(null); window.getSelection()?.removeAllRanges(); }}
        style={{ background: R, border: "none", borderRadius: 6, padding: "3px 10px", color: "#fff", fontSize: 11, cursor: "pointer", fontFamily: SF, fontWeight: 600 }}>
        📌 Save
      </button>
    </div>
  );
}


